const { ethers } = require('ethers');

class TokenSwapper {
  constructor(provider, signer, routerAddress) {
    this.provider = provider;
    this.signer = signer;
    this.routerAddress = routerAddress;
    this.router = new ethers.Contract(routerAddress, this.getRouterABI(), signer);
  }

  getRouterABI() {
    return [
      "function swapExactTokensForTokens(uint amountIn, uint amountOutMin, address[] calldata path, address to, uint deadline) external returns (uint[] memory amounts)",
      "function getAmountsOut(uint amountIn, address[] calldata path) external view returns (uint[] memory amounts)",
      "function approve(address spender, uint256 amount) external returns (bool)"
    ];
  }

  getTokenABI() {
    return [
      "function approve(address spender, uint256 amount) external returns (bool)",
      "function balanceOf(address account) external view returns (uint256)",
      "function decimals() external view returns (uint8)"
    ];
  }

  async approveToken(tokenAddress, amount = ethers.constants.MaxUint256) {
    try {
      const tokenContract = new ethers.Contract(tokenAddress, this.getTokenABI(), this.signer);
      const tx = await tokenContract.approve(this.routerAddress, amount);
      await tx.wait();
      return tx;
    } catch (error) {
      console.error('Approval failed:', error);
      throw error;
    }
  }

  async swapTokens(tokenIn, tokenOut, amountIn, recipient = null) {
    try {
      const path = [tokenIn, tokenOut];
      const deadline = Math.floor(Date.now() / 1000) + 60 * 20; // 20 minutes
      const to = recipient || await this.signer.getAddress();
      
      const amounts = await this.router.getAmountsOut(amountIn, path);
      const amountOutMin = amounts[1].mul(95).div(100); // 5% slippage
      
      const tx = await this.router.swapExactTokensForTokens(
        amountIn,
        amountOutMin,
        path,
        to,
        deadline
      );
      
      return await tx.wait();
    } catch (error) {
      console.error('Swap failed:', error);
      throw error;
    }
  }

  async getQuote(tokenIn, tokenOut, amountIn) {
    try {
      const path = [tokenIn, tokenOut];
      const amounts = await this.router.getAmountsOut(amountIn, path);
      return amounts[1];
    } catch (error) {
      console.error('Quote failed:', error);
      throw error;
    }
  }

  async ensureApproval(tokenAddress, amount) {
    try {
      const tokenContract = new ethers.Contract(tokenAddress, this.getTokenABI(), this.signer);
      const allowance = await tokenContract.allowance(await this.signer.getAddress(), this.routerAddress);
      
      if (allowance.lt(amount)) {
        await this.approveToken(tokenAddress, ethers.constants.MaxUint256);
      }
    } catch (error) {
      console.error('Approval check failed:', error);
      throw error;
    }
  }
}

// Usage example
async function main() {
  const provider = new ethers.providers.Web3Provider(window.ethereum);
  const signer = provider.getSigner();
  
  const swapper = new TokenSwapper(provider, signer, '0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D');
  
  // Approve tokens
  await swapper.ensureApproval('0xA0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48', ethers.utils.parseUnits('1000', 6));
  
  // Swap tokens
  const result = await swapper.swapTokens(
    '0xA0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48', // USDC
    '0x6B175474E89094C44Da98b954EedeAC495271d0F', // DAI
    ethers.utils.parseUnits('100', 6)
  );
  
  console.log('Swap successful:', result);
}